 38→export type AcceptanceTestRuntime = {
 39→  baseUrl: string;
 40→  surreal: Surreal;
 41→  namespace: string;
 42→  database: string;
 43→  port: number;
 44→};
 45→
 46→/** @deprecated Use `AcceptanceTestRuntime` instead. */
 47→export type SmokeTestRuntime = AcceptanceTestRuntime;
 48→
 49→export type AcceptanceSuiteOptions = {
 50→  /** Extra env vars to set before the server boots (e.g. ORCHESTRATOR_MOCK_AGENT). */
 51→  env?: Record<string, string>;
 52→};
 53→
 54→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 55→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 56→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 57→
 58→export function setupAcceptanceSuite(
 59→  suiteName: string,
 60→  options?: AcceptanceSuiteOptions,
 61→): () => AcceptanceTestRuntime {
 62→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 63→  const namespace = `accept_${runId}`;
 64→  const suiteSlug = suiteName
 65→    .toLowerCase()
 66→    .replace(/[^a-z0-9]+/g, "_")
 67→    .replace(/^_+|_+$/g, "");
 68→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
 69→
 70→  let runtime: AcceptanceTestRuntime | undefined;
 71→  let server: ReturnType<typeof Bun.serve> | undefined;
 72→  let runtimeSurreal: Surreal | undefined;
 73→  let analyticsSurreal: Surreal | undefined;
 74→  let inflight: InflightTracker | undefined;
 75→  let setupSucceeded = false;
 76→
 77→  beforeAll(async () => {
 78→    // Apply env overrides before server boot
 79→    if (options?.env) {
 80→      for (const [k, v] of Object.entries(options.env)) {
 81→        process.env[k] = v;
 82→      }
 83→    }
 84→
 85→    const surreal = new Surreal();
 86→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
 87→    await withTimeout(
 88→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
 89→      10_000,
 90→      "authenticate with SurrealDB",
 91→    );
 92→
 93→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
 94→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
 95→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
 96→    await withTimeout(
 97→      () => surreal.use({ namespace, database }),
 98→      10_000,
 99→      "switch to test namespace/database",
100→    );
101→
102→    const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
103→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
104→
105→    // Reserve a port so betterAuth gets the real URL at init time
106→    const tempServer = Bun.serve({ port: 0, fetch: () => new Response() });
107→    const reservedPort = tempServer.port;
108→    tempServer.stop(true);
109→    const baseUrl = `http://127.0.0.1:${reservedPort}`;
110→
111→    const config: ServerConfig = {
112→      openRouterApiKey: requireTestEnv("OPENROUTER_API_KEY"),
113→      chatAgentModelId: requireTestEnv("CHAT_AGENT_MODEL"),
114→      extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
115→      pmAgentModelId: process.env.PM_AGENT_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
116→      analyticsAgentModelId: requireTestEnv("ANALYTICS_MODEL"),
117→      embeddingModelId: requireTestEnv("EMBEDDING_MODEL"),
118→      embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
119→      extractionStoreThreshold: Number(requireTestEnv("EXTRACTION_STORE_THRESHOLD")),
120→      extractionDisplayThreshold: Number(requireTestEnv("EXTRACTION_DISPLAY_THRESHOLD")),
121→      surrealUrl,
122→      surrealUsername,
123→      surrealPassword,
124→      surrealNamespace: namespace,
125→      surrealDatabase: database,
126→      port: reservedPort,
127→      betterAuthSecret: process.env.BETTER_AUTH_SECRET ?? "smoke-test-secret-at-least-32-chars-long",
128→      betterAuthUrl: baseUrl,
129→      githubClientId: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
130→      githubClientSecret: process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
131→      observerModelId: process.env.OBSERVER_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
132→    };
133→
134→    const deps = await createRuntimeDependencies(config);
135→    runtimeSurreal = deps.surreal;
136→    analyticsSurreal = deps.analyticsSurreal;
137→    inflight = createInflightTracker();
138→
139→    const serverDeps: ServerDependencies = {
140→      config,
141→      surreal: deps.surreal,
142→      analyticsSurreal: deps.analyticsSurreal,
143→      auth: deps.auth,
144→      chatAgentModel: deps.chatAgentModel,
145→      extractionModel: deps.extractionModel,
146→      pmAgentModel: deps.pmAgentModel,
147→      analyticsAgentModel: deps.analyticsAgentModel,
148→      embeddingModel: deps.embeddingModel,
149→      observerModel: deps.observerModel,
150→      scorerModel: deps.scorerModel,
151→      sse: createSseRegistry(),
152→      inflight,
153→      asSigningKey: deps.asSigningKey,
154→      nonceCache: createNonceCache(),
155→    };
156→
157→    server = createBrainServer(serverDeps);
158→    const port = server.port;
159→
160→    runtime = { baseUrl, surreal, namespace, database, port };
161→    setupSucceeded = true;
162→  }, 60_000);
163→
164→  afterAll(async () => {
165→    // Drain fire-and-forget work (e.g. webhook extraction) before closing DB
166→    if (inflight) {
167→      await inflight.drain(15_000);
168→    }
169→
170→    if (server) {
171→      server.stop(true);
172→    }
173→
174→    if (runtimeSurreal) {
175→      await runtimeSurreal.close().catch(() => undefined);
176→    }
177→    if (analyticsSurreal) {
178→      await analyticsSurreal.close().catch(() => undefined);
179→    }
180→
181→    if (!runtime) {
182→      return;
183→    }
184→
185→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
186→      try {
187→        await withTimeout(() => runtime!.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
188→      } catch {
189→        // Best effort cleanup.
190→      }
191→
192→      try {
193→        await withTimeout(() => runtime!.surreal.query(`REMOVE NAMESPACE ${namespace};`), 10_000, "remove test namespace");
194→      } catch {
195→        // Best effort cleanup.
196→      }
197→    }
198→
199→    await withTimeout(() => runtime!.surreal.close(), 2_000, "close SurrealDB").catch(() => undefined);
200→  }, 20_000);
201→
202→  return () => {
203→    if (!runtime) {
204→      throw new Error("Acceptance runtime requested before suite setup completed");
205→    }
206→    return runtime;
207→  };
208→}
