221→export async function createTestUser(baseUrl: string, suffix: string): Promise<TestUser> {
222→  const email = `test-${Date.now()}-${suffix}@test.local`;
223→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
224→    method: "POST",
225→    headers: { "Content-Type": "application/json" },
226→    body: JSON.stringify({ name: "Test User", email, password: "test-password-123" }),
227→    redirect: "manual",
228→  });
229→
230→  if (!response.ok) {
231→    const body = await response.text();
232→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
233→  }
234→
235→  const setCookie = response.headers.getSetCookie();
236→  if (!setCookie || setCookie.length === 0) {
237→    throw new Error("Sign-up did not return session cookies");
238→  }
239→
240→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
241→  return { headers: { Cookie: cookieHeader } };
242→}
