244→// ---------------------------------------------------------------------------
245→// SSE Helpers
246→// ---------------------------------------------------------------------------
247→
248→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
249→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
250→  if (!response.ok || !response.body) {
251→    throw new Error(`Failed to open SSE stream (${response.status})`);
252→  }
253→
254→  const reader = response.body.getReader();
255→  const decoder = new TextDecoder();
256→  const events: T[] = [];
257→  let buffer = "";
258→
259→  const timeout = setTimeout(() => {
260→    void reader.cancel();
261→  }, timeoutMs);
262→
263→  try {
264→    while (true) {
265→      const { value, done } = await reader.read();
266→      if (done) {
267→        break;
268→      }
269→
270→      buffer += decoder.decode(value, { stream: true });
271→      const segments = buffer.split("\n\n");
272→      buffer = segments.pop() ?? "";
273→
274→      for (const segment of segments) {
275→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
276→        if (!dataLine) {
277→          continue;
278→        }
279→
280→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
281→        events.push(event);
282→
283→        if (event.type === "error") {
284→          const errorText = (event as { error?: string }).error;
285→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
286→        }
287→
288→        if (event.type === "done") {
289→          return events;
290→        }
291→      }
292→    }
293→  } finally {
294→    clearTimeout(timeout);
295→    reader.releaseLock();
296→  }
297→
298→  return events;
299→}
