305→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
306→  const response = await fetch(url, init);
307→  if (!response.ok) {
308→    const body = await response.text();
309→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
310→  }
311→
312→  return (await response.json()) as T;
