320→// OAuth Helpers
321→// ---------------------------------------------------------------------------
322→
323→function base64url(buf: Buffer): string {
324→  return buf.toString("base64url");
325→}
326→
327→function generatePkce(): { verifier: string; challenge: string } {
328→  const verifier = base64url(randomBytes(32));
329→  const challenge = base64url(createHash("sha256").update(verifier).digest());
330→  return { verifier, challenge };
331→}
