333→/**
334→ * Obtain an OAuth2 JWT access token for MCP endpoints.
335→ * Requires a SurrealDB connection to skip consent screen.
336→ */
337→export async function getOAuthToken(
338→  baseUrl: string,
339→  surreal: Surreal,
340→  sessionHeaders: Record<string, string>,
341→  scopes: string = "graph:read graph:reason session:write offline_access",
342→): Promise<string> {
343→  // Trigger JWKS key generation if not yet done
344→  await fetch(`${baseUrl}/api/auth/jwks`);
345→
346→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
347→    method: "POST",
348→    headers: { "Content-Type": "application/json" },
349→    body: JSON.stringify({
350→      client_name: `test-client-${Date.now()}`,
351→      redirect_uris: ["http://127.0.0.1:9999/callback"],
352→      grant_types: ["authorization_code", "refresh_token"],
353→      response_types: ["code"],
354→      token_endpoint_auth_method: "none",
355→    }),
356→  });
357→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
358→
359→  const { client_id } = (await dcrRes.json()) as { client_id: string };
360→
361→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
362→    cid: client_id,
363→  });
364→
365→  const { verifier, challenge } = generatePkce();
366→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
367→  authUrl.searchParams.set("client_id", client_id);
368→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
369→  authUrl.searchParams.set("response_type", "code");
370→  authUrl.searchParams.set("scope", scopes);
371→  authUrl.searchParams.set("state", "test-state");
372→  authUrl.searchParams.set("code_challenge", challenge);
373→  authUrl.searchParams.set("code_challenge_method", "S256");
374→  authUrl.searchParams.set("resource", baseUrl);
375→
376→  const authRes = await fetch(authUrl.toString(), {
377→    headers: sessionHeaders,
378→    redirect: "manual",
379→  });
380→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
381→
382→  const location = authRes.headers.get("location")!;
383→  const redirectUrl = new URL(location, baseUrl);
384→  const code = redirectUrl.searchParams.get("code") ?? "";
385→  if (!code) throw new Error(`No code in redirect: ${location}`);
386→
387→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
388→    method: "POST",
389→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
390→    body: new URLSearchParams({
391→      grant_type: "authorization_code",
392→      code,
393→      redirect_uri: "http://127.0.0.1:9999/callback",
394→      client_id,
395→      code_verifier: verifier,
