590→// ---------------------------------------------------------------------------
591→// DPoP Helpers
592→// ---------------------------------------------------------------------------
593→
594→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
595→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
596→    { name: "ECDSA", namedCurve: "P-256" },
597→    true,
598→    ["sign", "verify"],
599→  );
600→
601→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
602→  const thumbprint = await computeDPoPThumbprint(publicJwk);
603→
604→  return { privateKey, publicKey, publicJwk, thumbprint };
605→}
606→
607→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
608→  const thumbprintInput = JSON.stringify({
609→    crv: publicJwk.crv,
610→    kty: publicJwk.kty,
611→    x: publicJwk.x,
612→    y: publicJwk.y,
613→  });
614→
615→  const hashBuffer = await crypto.subtle.digest(
616→    "SHA-256",
617→    new TextEncoder().encode(thumbprintInput),
618→  );
619→
620→  return base64urlBytes(new Uint8Array(hashBuffer));
621→}
622→
623→async function createDPoPProof(
624→  keyPair: DPoPKeyPair,
625→  method: string,
626→  targetUri: string,
627→): Promise<string> {
628→  const header = {
629→    typ: "dpop+jwt" as const,
630→    alg: "ES256" as const,
631→    jwk: {
632→      kty: keyPair.publicJwk.kty,
633→      crv: keyPair.publicJwk.crv,
634→      x: keyPair.publicJwk.x,
635→      y: keyPair.publicJwk.y,
636→    },
637→  };
638→
639→  const payload = {
640→    jti: crypto.randomUUID(),
641→    htm: method,
642→    htu: targetUri,
643→    iat: Math.floor(Date.now() / 1000),
644→  };
645→
646→  const importedKey = await jose.importJWK(
647→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
648→    "ES256",
649→  );
650→
651→  return await new jose.SignJWT(payload)
652→    .setProtectedHeader(header)
653→    .sign(importedKey);
654→}
655→
656→function base64urlBytes(bytes: Uint8Array): string {
657→  const binary = String.fromCharCode(...bytes);
658→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
659→}
