  1→/**
  2→ * LLM Proxy Acceptance Test Kit
  3→ *
  4→ * Domain-specific helpers for LLM proxy acceptance tests.
  5→ * Extends the shared acceptance-test-kit with proxy-specific
  6→ * workspace setup, request builders, and graph query helpers.
  7→ *
  8→ * Driving ports: HTTP endpoints at /proxy/llm/anthropic/v1/messages
  9→ * and /api/workspaces/:workspaceId/proxy/spend
 10→ */
 11→import { RecordId, type Surreal } from "surrealdb";
 12→import {
 13→  setupAcceptanceSuite,
 14→  createTestUser,
 15→  fetchRaw,
 16→  type AcceptanceTestRuntime,
 17→  type TestUser,
 18→} from "../acceptance-test-kit";
 19→
 20→// Re-export shared helpers
 21→export {
 22→  setupAcceptanceSuite,
 23→  createTestUser,
 24→  fetchRaw,
 25→  type AcceptanceTestRuntime,
 26→  type TestUser,
 27→};
 28→
 29→// ---------------------------------------------------------------------------
 30→// Proxy Request Builders
 31→// ---------------------------------------------------------------------------
 32→
 33→export type ProxyRequestOptions = {
 34→  model: string;
 35→  stream?: boolean;
 36→  maxTokens?: number;
 37→  messages?: Array<{ role: string; content: string }>;
 38→  metadata?: { user_id?: string };
 39→  apiKey?: string;
 40→  workspaceHeader?: string;
 41→  taskHeader?: string;
 42→  agentTypeHeader?: string;
 43→};
 44→
 45→/**
 46→ * Build a proxy request body matching the Anthropic Messages API format.
 47→ */
 48→export function buildProxyRequestBody(options: ProxyRequestOptions): string {
 49→  return JSON.stringify({
 50→    model: options.model,
 51→    max_tokens: options.maxTokens ?? 100,
 52→    stream: options.stream ?? false,
 53→    messages: options.messages ?? [
 54→      { role: "user", content: "Say hello in one word." },
 55→    ],
 56→    ...(options.metadata ? { metadata: options.metadata } : {}),
 57→  });
 58→}
 59→
 60→/**
 61→ * Build headers for a proxy request, including identity headers.
 62→ */
 63→export function buildProxyHeaders(options: ProxyRequestOptions): Record<string, string> {
 64→  const headers: Record<string, string> = {
 65→    "Content-Type": "application/json",
 66→    "anthropic-version": "2023-06-01",
 67→  };
 68→
 69→  if (options.apiKey) {
 70→    headers["x-api-key"] = options.apiKey;
 71→  }
 72→  if (options.workspaceHeader) {
 73→    headers["X-Brain-Workspace"] = options.workspaceHeader;
 74→  }
 75→  if (options.taskHeader) {
 76→    headers["X-Brain-Task"] = options.taskHeader;
 77→  }
 78→  if (options.agentTypeHeader) {
 79→    headers["X-Brain-Agent-Type"] = options.agentTypeHeader;
 80→  }
 81→
 82→  return headers;
 83→}
 84→
 85→/**
 86→ * Send a request through the LLM proxy endpoint.
 87→ * Returns the raw Response for flexible assertion.
 88→ */
 89→export async function sendProxyRequest(
 90→  baseUrl: string,
 91→  options: ProxyRequestOptions,
 92→): Promise<Response> {
 93→  const body = buildProxyRequestBody(options);
 94→  const headers = buildProxyHeaders(options);
 95→
 96→  return fetch(`${baseUrl}/proxy/llm/anthropic/v1/messages`, {
 97→    method: "POST",
 98→    headers,
 99→    body,
100→  });
101→}
102→
103→/**
104→ * Send a count_tokens request through the proxy.
105→ */
106→export async function sendCountTokensRequest(
107→  baseUrl: string,
108→  options: ProxyRequestOptions,
109→): Promise<Response> {
110→  const body = buildProxyRequestBody(options);
111→  const headers = buildProxyHeaders(options);
112→
113→  return fetch(`${baseUrl}/proxy/llm/anthropic/v1/messages/count_tokens`, {
114→    method: "POST",
115→    headers,
116→    body,
117→  });
118→}
119→
120→// ---------------------------------------------------------------------------
121→// SSE Stream Helpers
122→// ---------------------------------------------------------------------------
123→
124→export type SSEEvent = {
125→  event?: string;
126→  data: string;
127→};
128→
129→/**
130→ * Collect all SSE events from a streaming proxy response.
131→ */
132→export async function collectProxySSEEvents(response: Response): Promise<SSEEvent[]> {
133→  if (!response.body) {
134→    throw new Error("No response body for SSE collection");
135→  }
136→
137→  const reader = response.body.getReader();
138→  const decoder = new TextDecoder();
139→  const events: SSEEvent[] = [];
140→  let buffer = "";
141→
142→  try {
143→    while (true) {
144→      const { done, value } = await reader.read();
145→      if (done) break;
146→
147→      buffer += decoder.decode(value, { stream: true });
148→      const segments = buffer.split("\n\n");
149→      buffer = segments.pop() ?? "";
150→
151→      for (const segment of segments) {
152→        const lines = segment.split("\n");
153→        let eventType: string | undefined;
154→        let dataLine: string | undefined;
155→
156→        for (const line of lines) {
157→          if (line.startsWith("event: ")) {
158→            eventType = line.slice(7);
159→          } else if (line.startsWith("data: ")) {
160→            dataLine = line.slice(6);
161→          }
162→        }
163→
164→        if (dataLine !== undefined) {
165→          events.push({ event: eventType, data: dataLine });
166→        }
167→      }
168→    }
169→  } finally {
170→    reader.releaseLock();
171→  }
172→
173→  return events;
174→}
175→
176→// ---------------------------------------------------------------------------
177→// Workspace and Identity Setup
178→// ---------------------------------------------------------------------------
179→
180→/**
181→ * Create a workspace record in SurrealDB for proxy testing.
182→ */
183→export async function createProxyTestWorkspace(
184→  surreal: Surreal,
185→  workspaceId: string,
186→  options?: { dailyBudget?: number; alertThreshold?: number },
187→): Promise<string> {
188→  const workspaceRecord = new RecordId("workspace", workspaceId);
189→
190→  await surreal.query(`CREATE $workspace CONTENT $content;`, {
191→    workspace: workspaceRecord,
192→    content: {
193→      name: `Proxy Test Workspace ${workspaceId}`,
194→      status: "active",
195→      onboarding_complete: true,
196→      onboarding_turn_count: 0,
197→      onboarding_summary_pending: false,
198→      onboarding_started_at: new Date(),
199→      created_at: new Date(),
200→      proxy_settings: {
201→        daily_budget: options?.dailyBudget ?? 50.0,
202→        alert_threshold: options?.alertThreshold ?? 0.8,
203→        rate_limit_per_minute: 60,
204→      },
205→    },
206→  });
207→
208→  return workspaceId;
209→}
210→
211→/**
212→ * Create a project record linked to a workspace.
213→ */
214→export async function createProxyTestProject(
215→  surreal: Surreal,
216→  projectId: string,
217→  workspaceId: string,
218→): Promise<string> {
219→  const projectRecord = new RecordId("project", projectId);
220→  const workspaceRecord = new RecordId("workspace", workspaceId);
221→
222→  await surreal.query(`CREATE $project CONTENT $content;`, {
223→    project: projectRecord,
224→    content: {
225→      title: `Test Project ${projectId}`,
226→      status: "active",
227→      workspace: workspaceRecord,
228→      created_at: new Date(),
229→    },
230→  });
231→
232→  return projectId;
233→}
234→
235→/**
236→ * Create a task record linked to a project and workspace.
237→ */
238→export async function createProxyTestTask(
239→  surreal: Surreal,
240→  taskId: string,
241→  projectId: string,
242→  workspaceId: string,
243→): Promise<string> {
