/**
 * Create a model access policy for the proxy.
 */
export async function createModelAccessPolicy(
  surreal: Surreal,
  workspaceId: string,
  options: {
    policyId: string;
    agentType: string;
    allowedModels: string[];
    status?: string;
  },
): Promise<string> {
